## 自定义 useFormValidation 钩子

```typescript
import { useState, useCallback } from 'react';

interface ValidationRule {
  required?: boolean;
  minLength?: number;
  maxLength?: number;
  pattern?: RegExp;
  custom?: (value: string) => string | null;
}

interface FormConfig {
  [field: string]: ValidationRule;
}

export function useFormValidation<T extends Record<string, string>>(
  initialValues: T,
  validationRules: FormConfig
) {
  const [values, setValues] = useState(initialValues);
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [touched, setTouched] = useState<Record<string, boolean>>({});

  const validate = useCallback((field: string, value: string) => {
    const rules = validationRules[field];
    if (!rules) return null;

    if (rules.required && !value.trim()) {
      return '此字段为必填项';
    }
    if (rules.minLength && value.length < rules.minLength) {
      return `最少需要 ${rules.minLength} 个字符`;
    }
    return null;
  }, [validationRules]);

  const handleChange = useCallback((field: string, value: string) => {
    setValues(prev => ({ ...prev, [field]: value }));
    const error = validate(field, value);
    setErrors(prev => ({ ...prev, [field]: error || '' }));
  }, [validate]);

  return { values, errors, touched, handleChange };
}
```

### 核心功能

- **类型安全**：通过泛型提供完整的 TypeScript 支持
- **灵活验证**：支持必填、长度、正则和自定义规则
- **触碰追踪**：仅在用户交互后显示错误
- **高性能**：使用 `useCallback` 避免不必要的重新渲染

